    if (!fb) return;

    // 转换为 HSV 并分割红色区域
    int red_pixels = 0;
    int center_x = 0, center_y = 0;

    for (int y = 0; y < fb->height; y++) {
        for (int x = 0; x < fb->width; x++) {
            // 像素颜色转换和阈值判断
            // ...
            if (isRedPixel) {
                red_pixels++;
                center_x += x;
                center_y += y;
            }
        }
    }

    // 计算中心点
    if (red_pixels > 0) {
        center_x /= red_pixels;
        center_y /= red_pixels;
        // 控制无人机追踪红色物体
        // ...
    }

    esp_camera_fb_return(fb);
}
```

